240.         public async ValueTask<OperationState> UpdateStateAsync(bool async, CancellationToken cancellationToken)
241.         {
242.             Response response = async
243.                 ? await GetResponseAsync(_nextRequestUri, cancellationToken).ConfigureAwait(false)
244.                 : GetResponse(_nextRequestUri, cancellationToken);
245. 
246.             var hasCompleted = IsFinalState(response, _headerSource, out var failureState, out var resourceLocation);
247.             if (failureState != null)
248.             {
249.                 return failureState.Value;
250.             }
251. 
