                {
                    code = property.Value.GetString();
                }
                else if (property.NameEquals("innererror"))
                {
                    innerError = ReadResponseInnerError(property.Value);
                }
            }

            return new ResponseInnerError(code, innerError);
        }

        private static void WriteResponseInnerError(Utf8JsonWriter writer, ResponseInnerError innerError)
        {
            writer.WriteStartObject();
            if (innerError.Code != null)
